class Solution {
    public int integerReplacement(int n) {
        int steps = 0;
        while (n > 1) {
            if (n % 2 == 0) {
                n /= 2;
                steps++;
            } else {
                if (n == 3) {
                    n = 2;
                    steps++;
                } else {
                    int x = n + 1;
                    if ((x & (x - 1)) == 0) {
                        n = x;
                        steps++;
                    } else {
                        n--;
                        steps++;
                    }
                }
            }
        }
        return steps;
    }
}

